return [{
  json: {
    META_ACCESS_TOKEN: 'SEU_ACCESS_TOKEN_AQUI',
    META_API_BASE: 'https://graph.facebook.com/v21.0',
    BATCH_SIZE: 50,
    SUPABASE_URL: 'https://bfumywvwubvernvhjehk.supabase.co',
    SUPABASE_KEY: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJmdW15d3Z3dWJ2ZXJudmhqZWhrIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc1MTQwMzc5OSwiZXhwIjoyMDY2OTc5Nzk5fQ.fdTsdGlSqemXzrXEU4ov1SUpeDn_3bSjOingqkSAWQE'
  }
}];

// Coletar todos os ad_ids de fb_ads_performance
const allRaw = $('Supabase Get Ad IDs').all();
const allAdIds = [];
const seen = new Set();

for (const item of allRaw) {
  const val = item.json;
  // O PostgREST retorna um array de objetos na raiz OU um unico objeto
  if (Array.isArray(val)) {
    val.forEach(r => { if (r.ad_id && !seen.has(r.ad_id)) { seen.add(r.ad_id); allAdIds.push(r.ad_id); } });
  } else if (val && val.ad_id && !seen.has(val.ad_id)) {
    seen.add(val.ad_id);
    allAdIds.push(val.ad_id);
  }
}

// Coletar ad_ids frescos (fetchados nos ultimos 7 dias)
const freshRaw = $('Supabase Get Existing').all();
const freshSet = new Set();

for (const item of freshRaw) {
  const val = item.json;
  if (Array.isArray(val)) {
    val.forEach(r => { if (r.ad_id) freshSet.add(r.ad_id); });
  } else if (val && val.ad_id) {
    freshSet.add(val.ad_id);
  }
}

// Filtrar apenas os que precisam ser fetchados
const toFetch = allAdIds.filter(id => !freshSet.has(id));

console.log(`Total ad_ids: ${allAdIds.length} | Frescos: ${freshSet.size} | A buscar: ${toFetch.length}`);

if (toFetch.length === 0) {
  return [{ json: { ad_id: '__SKIP__', total_to_fetch: 0, message: 'Todos ad_ids ja sao frescos' } }];
}

return toFetch.map(ad_id => ({ json: { ad_id } }));

// Montar URL do batch para a Meta Graph API
// Formato: /?ids=ID1,ID2,...&fields=creative{...}&access_token=TOKEN
const items = $input.all();
const ids = items.map(item => item.json.ad_id).filter(Boolean).join(',');

const config = $('Config').first().json;
const fields = 'creative{thumbnail_url,image_url,video_id,title,body}';
const url = `${config.META_API_BASE}/?ids=${encodeURIComponent(ids)}&fields=${encodeURIComponent(fields)}&access_token=${config.META_ACCESS_TOKEN}`;

console.log(`Batch de ${items.length} IDs preparado`);

return [{ json: { ids_csv: ids, id_count: items.length, meta_url: url } }];

// Parsear resposta da Meta API
// Formato da resposta: { "AD_ID": { "creative": { thumbnail_url, image_url, video_id, title, body }, "id": "AD_ID" }, ... }

const response = $input.first().json;

// Checar erro de API
if (response.error) {
  console.error('Meta API Error:', JSON.stringify(response.error));
  return [{
    json: {
      _meta_error: true,
      error_code: response.error.code,
      error_message: response.error.message
    }
  }];
}

const now = new Date().toISOString();
const results = [];

for (const [adId, adData] of Object.entries(response)) {
  if (adId === 'error' || !adData || typeof adData !== 'object') continue;

  const creative = adData.creative || {};

  let creativeType = 'image';
  if (creative.video_id) creativeType = 'video';
  else if (!creative.thumbnail_url && !creative.image_url) creativeType = 'unknown';

  results.push({
    json: {
      ad_id: adId,
      thumbnail_url: creative.thumbnail_url || null,
      image_url: creative.image_url || null,
      video_id: creative.video_id || null,
      title: creative.title || null,
      body: creative.body || null,
      creative_type: creativeType,
      fetched_at: now,
      updated_at: now
    }
  });
}

console.log(`Parse concluido: ${results.length} criativos extraidos da resposta Meta API`);

if (results.length === 0) {
  return [{ json: { _empty: true } }];
}

return results;

// Sumarizar resultado final
const raw = $input.first().json;
const all = raw.all_results || [];

const total = all.length;
const withThumb = all.filter(r => r.thumbnail_url).length;
const withImage = all.filter(r => r.image_url).length;
const withVideo = all.filter(r => r.video_id).length;
const errors = all.filter(r => r._meta_error).length;

const summary = {
  execution_time: new Date().toISOString(),
  total_processed: total,
  with_thumbnail: withThumb,
  with_image_url: withImage,
  with_video_id: withVideo,
  errors: errors,
  success_rate: total > 0 ? `${Math.round((total - errors) / total * 100)}%` : 'N/A'
};

console.log('Resumo da execucao:', JSON.stringify(summary, null, 2));
return [{ json: summary }];

// Nenhum ad_id novo para processar
const data = $('Code: Filter New').first().json;
const msg = data.message || 'Todos ad_ids ja sao frescos - sem acao necessaria';
console.log(msg);
return [{ json: { skipped: true, message: msg, execution_time: new Date().toISOString() } }];
